import React from "react";
import UploadImage from "./UploadImage";

function App() {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-100 p-6">
      <div className="bg-white shadow-xl rounded-xl p-8 max-w-3xl text-center">
        <h1 className="text-4xl font-extrabold text-gray-800">Radiology & Oncology AI</h1>
        <p className="text-gray-600 mt-2 text-lg">
          Upload a medical image to receive AI-powered diagnostic insights.
        </p>

        <div className="mt-6">
          <UploadImage />
        </div>

        <p className="mt-6 text-gray-500 text-sm">
          This AI assists in radiology image analysis but is not a replacement for professional medical advice.
        </p>
      </div>

      <footer className="mt-8 text-gray-500 text-sm">
        © 2025 Radiology AI. All rights reserved.
      </footer>
    </div>
  );
}

export default App;
